<template>
  <v-row justify="center">
    <v-dialog
      :model-value="dialog"
      transition="dialog-bottom-transition"
      fullscreen
    >
      <v-card class="mx-auto card">
        <v-toolbar dark color="#624fc6">
          <v-btn
            icon
            fab
            color="#ffffff"
            x-small
            @click="$emit('popClose')"
            class="mr-1"
          >
            <Icon
              class="icon_download"
              icon="ic:outline-close"
              color="#ffffff"
              width="25"
            />
          </v-btn>

          <v-toolbar-title class="mx-auto d-flex justify-center">
            <h3 style="font-family: 'Cairo', sans-serif">اضافة منتجات</h3>
          </v-toolbar-title>
        </v-toolbar>

        <v-form ref="add_goods_form">
          <v-card-text class="mt-2">
            <v-row>
              <v-col cols="12" sm="12" md="12" lg="3">
                <Input
                  v-model="product"
                  @update-value="product = $event"
                  autocomplete="product"
                  type="text"
                  label="اسم المنتج"
                  :rules="NameRulse"
                />
              </v-col>
              <v-col cols="12" sm="12" md="12" lg="3">
                <Selects
                  v-on:update-value="type = $event"
                  v-model="type"
                  label="نوع المنتج"
                  itemValue="value"
                  itemText="type"
                  :items="types"
                  :rules="AllRulse"
                />
              </v-col>

              <v-col cols="12" sm="12" md="12" lg="3">
                <Input
                  v-model="barcode"
                  @update-value="barcode = $event"
                  type="text"
                  label="باركود المنتج"
                  :rules="NameRulse"
                />
              </v-col>
              <v-col cols="12" sm="12" md="12" lg="3">
                <Input
                  v-model="model"
                  @update-value="model = $event"
                  type="number"
                  label="الموديل"
                />
              </v-col>
              <v-col cols="12" sm="12" md="12" lg="3">
                <Input
                  v-model="total_pieces"
                  @update-value="total_pieces = $event"
                  autocomplete="total_pieces"
                  type="Number"
                  label="عدد القطع الكلي"
                  :rules="AllRulse"
                  :min="1"
                  :max="30"
                />
              </v-col>
              <v-col cols="2" sm="2" md="2" lg="1" class="mt-2">
                <VSwatches v-model="color" :swatches="swatches" />
              </v-col>
              <v-col cols="12" sm="12" md="12" lg="4">
                <Input
                  v-model="purchase_price"
                  @update-value="purchase_price = $event"
                  autocomplete="purchase_price"
                  type="Number"
                  label="سعر الشراء"
                />
              </v-col>
              <v-col cols="12" sm="12" md="12" lg="4">
                <v-text-field
                  class="font-weight-black"
                  :model-value="displayPrice"
                  type="text"
                  label="سعر البيع"
                  color="#624fc6"
                  variant="outlined"
                  rounded
                  clearable
                  autocomplete="selling_price"
                  lazy-rules
                  persistent-hint
                  :rules="NameRulse"
                  hide-details="auto"
                  @update:modelValue="onInput"
                  @keypress="allowOnlyNumbers"
                />
              </v-col>

              <v-row v-if="sizes.length > 0" dense>
                <template v-for="(size, index) in sizes" :key="index">
                  <v-col cols="6" sm="3" md="2" lg="2">
                    <Input
                      v-model="size.size"
                      @update-value="size.size = $event"
                      autocomplete="size"
                      type="text"
                      label="مثلاً S, M المقاس"
                      :rules="SizeRulse"
                    />
                  </v-col>
                  <v-col cols="6" sm="3" md="2" lg="2">
                    <Input
                      v-model="size.quantity"
                      @update-value="size.quantity = $event"
                      autocomplete="label"
                      type="Number"
                      label="عدد القطع"
                      :rules="AllRulse"
                    />
                  </v-col>
                </template>
              </v-row>
            </v-row>
          </v-card-text>
          <v-card-actions class="mt-1">
            <v-btn
              @click="add_goods"
              :loading="loading"
              color="#624fc6"
              elevation="4"
              variant="flat"
              size="large"
              class="mx-auto border-btn"
            >
              <h4 style="color: white; font-size: 17px">اضافة</h4>
              <template v-slot:loader>
                <span class="custom-loader">
                  <v-icon color="white">mdi-cached</v-icon>
                </span>
              </template>
            </v-btn>
          </v-card-actions>
        </v-form>
      </v-card>
    </v-dialog>
  </v-row>
</template>

<script setup>
import { ref, watch, computed } from "vue";
import Input from "../layout/Input.vue";
import Selects from "../layout/Selects.vue";
import { useGoodsStore } from "@/stores/goods";
const goodsStore = useGoodsStore();

defineProps({
  dialog: {
    type: Boolean,
    default: false,
  },
});
const swatches = [
  "#000000",
  "#FFFFFF",
  "#FF0000",
  "#00FF00",
  "#0000FF",
  "#4B0082",
  "#FFFF00",
  "#800080",
  "#00FFFF",
  "#FFC0CB",
  "#FFA500",
  "#808080",
  "#A52A2A",
  "#FFD700",
  "#C0C0C0",
  "#800000",
  "#8B4000",
  "#826644",
];
const add_goods_form = ref(null);
const type = ref(null);
const barcode = ref(null);
const purchase_price = ref(null);
const selling_price = ref(null);
const model = ref(null);
const color = ref("#000000");
const product = ref("");
const total_pieces = ref(0);
const sizes = ref([]); // كل عنصر: { size: "", quantity: null, index: 0 }
const types = [
  { name: "type", type: "ملابس", value: 0 },
  { name: "type", type: "احذية", value: 1 },
];

const NameRulse = [
  (value) => !!value || "هذا الحقل مطلوب",
  (value) => (value || "").length >= 3 || "الحد الادنى لعدد الاحرف هوه 3",
];

const SizeRulse = [
  (value) => !!value || "هذا الحقل مطلوب",
  (value) => (value || "").length >= 1 || "الحد الادنى لعدد الاحرف هوه 1",
  (value) => (value || "").length <= 3 || "الحد الاقصى لعدد الاحرف هوه 3",
];

const AllRulse = [(value) => !!value || "هذا الحقل مطلوب"];

const add_goods = async () => {
  const isValid = await add_goods_form.value.validate();
  if (isValid.valid) {
    // بَنّي مصفوفة variants مع index حقيقي وقيم رقمية للكمية
    const variants = sizes.value.map((v, idx) => {
      return {
        index: idx, // <-- هنا ال index مضاف
        size: v.size,
        quantity: Number(v.quantity) || 0,
      };
    });

    let data = {
      name: product.value,
      type: type.value?.value,
      barcode: barcode.value,
      total_pieces: total_pieces.value,
      color: color.value,
      purchase_price: purchase_price.value,
      selling_price: selling_price.value,
      variants: variants,
      model: model.value,
    };

    try {
      await goodsStore.add_goods(data);
      add_goods_form.value.reset(); // Reset after adding
      // إعادة تهيئة sizes أيضاً لو تحب:
      sizes.value = [];
      total_pieces.value = 0;
    } catch (e) {
      console.error("Error in store", e);
    }
  }
};

const displayPrice = computed(() => {
  if (!selling_price.value) return "";
  return new Intl.NumberFormat("en-US").format(Number(selling_price.value));
});

const onInput = (val) => {
  const str = (val ?? "").toString(); // لو val null أو undefined يصبح ""
  selling_price.value = str.replace(/\D/g, "");
};
// منع أي حرف غير رقم أثناء الكتابة
const allowOnlyNumbers = (event) => {
  const key = event.key;
  if (!/^[0-9]$/.test(key)) {
    event.preventDefault();
  }
};

const loading = computed(() => goodsStore.add_product_loading);

// عند تغير total_pieces نولد الصفوف المطلوبة
watch(total_pieces, (newVal) => {
  const currentLength = sizes.value.length;

  if (newVal > currentLength) {
    for (let i = currentLength; i < newVal; i++) {
      sizes.value.push({ size: "", quantity: null, index: i });
    }
  } else if (newVal < currentLength) {
    sizes.value.splice(newVal); // حذف العناصر الزائدة فقط
  }

  // أعد ترقيم ال index بعد أي تغيير للتأكد من التسلسل الصحيح
  sizes.value.forEach((s, idx) => {
    s.index = idx;
  });
});
</script>

<style scoped>
.card {
  box-shadow: 0px 0px 0px 0px !important;
}
</style>
